import{_ as r,c as s,o,a5 as t,j as e}from"./chunks/framework.Dtwt352Q.js";const u=JSON.parse('{"title":"v1.2.9: MCP Attachment Fix, Performance Optimization","description":"","frontmatter":{},"headers":[],"relativePath":"en/changelog/v1.2.9.md","filePath":"en/changelog/v1.2.9.md","lastUpdated":1772014034000}'),n={name:"en/changelog/v1.2.9.md"};function i(d,a,l,c,h,m){return o(),s("div",null,[...a[0]||(a[0]=[t('<h1 id="v1-2-9-mcp-attachment-fix-performance-optimization" tabindex="-1">v1.2.9: MCP Attachment Fix, Performance Optimization <a class="header-anchor" href="#v1-2-9-mcp-attachment-fix-performance-optimization" aria-label="Permalink to “v1.2.9: MCP Attachment Fix, Performance Optimization”">​</a></h1><p><strong>Release Date</strong>: 2026-02-20</p><p>This version fixes the <strong>issue of missing IDs in MCP tool attachments</strong>, and includes several performance optimizations.</p><h2 id="🎯-one-sentence-summary" tabindex="-1">🎯 One-Sentence Summary <a class="header-anchor" href="#🎯-one-sentence-summary" aria-label="Permalink to “🎯 One-Sentence Summary”">​</a></h2><p>Fixed MCP tool attachment ID missing issue; use native structuredClone for better performance; desktop restored settings header mask.</p><hr><h2 id="🐛-bug-fixes" tabindex="-1">🐛 Bug Fixes <a class="header-anchor" href="#🐛-bug-fixes" aria-label="Permalink to “🐛 Bug Fixes”">​</a></h2><h3 id="mcp-tool-attachment-id-fix" tabindex="-1">MCP Tool Attachment ID Fix <a class="header-anchor" href="#mcp-tool-attachment-id-fix" aria-label="Permalink to “MCP Tool Attachment ID Fix”">​</a></h3><p>MCP tool attachments now include correct <code>id</code>, <code>sessionID</code>, and <code>messageID</code>.</p><p><strong>Impact</strong>: Previously, some attachments returned by MCP tools might not be correctly associated with sessions; now fixed.</p><hr><h2 id="⚡-performance-optimizations" tabindex="-1">⚡ Performance Optimizations <a class="header-anchor" href="#⚡-performance-optimizations" aria-label="Permalink to “⚡ Performance Optimizations”">​</a></h2><h3 id="using-native-structuredclone" tabindex="-1">Using Native structuredClone <a class="header-anchor" href="#using-native-structuredclone" aria-label="Permalink to “Using Native structuredClone”">​</a></h3><p>TUI now uses JavaScript&#39;s native <code>structuredClone</code> instead of remeda library&#39;s <code>clone</code> function.</p><p><strong>Benefits</strong>: Better performance and native support.</p><hr><h3 id="removed-unnecessary-deep-clones" tabindex="-1">Removed Unnecessary Deep Clones <a class="header-anchor" href="#removed-unnecessary-deep-clones" aria-label="Permalink to “Removed Unnecessary Deep Clones”">​</a></h3><p>Removed unnecessary deep clone operations from session loop and LLM stream, improving processing speed.</p><hr><h3 id="test-fix" tabindex="-1">Test Fix <a class="header-anchor" href="#test-fix" aria-label="Permalink to “Test Fix”">​</a></h3><p>Removed User-Agent assertion from LLM tests, fixing test failure issues.</p><hr><h2 id="🖥️-desktop-updates" tabindex="-1">🖥️ Desktop Updates <a class="header-anchor" href="#🖥️-desktop-updates" aria-label="Permalink to “🖥️ Desktop Updates”">​</a></h2><h3 id="restored-settings-header-mask" tabindex="-1">Restored Settings Header Mask <a class="header-anchor" href="#restored-settings-header-mask" aria-label="Permalink to “Restored Settings Header Mask”">​</a></h3><p>Restored the settings interface header mask display in desktop.</p><hr><h2 id="📊-should-you-upgrade" tabindex="-1">📊 Should You Upgrade? <a class="header-anchor" href="#📊-should-you-upgrade" aria-label="Permalink to “📊 Should You Upgrade?”">​</a></h2><table tabindex="0"><thead><tr><th>Situation</th><th>Recommendation</th></tr></thead><tbody><tr><td>Using MCP tools</td><td>✅ Recommended</td></tr><tr><td>Care about performance</td><td>✅ Recommended</td></tr><tr><td>Everything works fine</td><td>⚪ Optional upgrade</td></tr></tbody></table><hr><h2 id="⬆️-upgrade-command" tabindex="-1">⬆️ Upgrade Command <a class="header-anchor" href="#⬆️-upgrade-command" aria-label="Permalink to “⬆️ Upgrade Command”">​</a></h2>',30),e("div",{class:"language-bash"},[e("button",{title:"Copy Code",class:"copy"}),e("span",{class:"lang"},"bash"),e("pre",null,[e("code",{"v-pre":""},"opencode upgrade")])],-1),t('<hr><h2 id="📋-technical-details" tabindex="-1">📋 Technical Details <a class="header-anchor" href="#📋-technical-details" aria-label="Permalink to “📋 Technical Details”">​</a></h2><details><summary>Click to expand original Release Notes</summary><h2 id="core" tabindex="-1">Core <a class="header-anchor" href="#core" aria-label="Permalink to “Core”">​</a></h2><ul><li>Add missing id, sessionID, and messageID to MCP tool attachments (@NatChung)</li><li>Remove unnecessary deep clones from session loop and LLM stream</li><li>Remove User-Agent header assertion from LLM test to fix failing test</li></ul><h2 id="tui" tabindex="-1">TUI <a class="header-anchor" href="#tui" aria-label="Permalink to “TUI”">​</a></h2><ul><li>Use structuredClone instead of remeda&#39;s clone for better performance and native support (@mhart)</li></ul><h2 id="desktop" tabindex="-1">Desktop <a class="header-anchor" href="#desktop" aria-label="Permalink to “Desktop”">​</a></h2><ul><li>Restore settings header mask</li></ul><p><strong>Thank you to 2 community contributors:</strong></p><ul><li>@mhart: Use structuredClone instead of remeda&#39;s clone</li><li>@NatChung: fix: add missing id/sessionID/messageID to MCP tool attachments</li></ul></details><hr><p><a href="./">← Back to Changelog</a></p>',5)])])}const f=r(n,[["render",i]]);export{u as __pageData,f as default};
